const domain = $('Normalize Input').first().json.asset_value;
const engId = $('Normalize Input').first().json.engagement_id;
const assetId = $('Normalize Input').first().json.asset_id;
const scanJobId = $('Create Scan Job').first().json.id;

// Parse A records
let aRecords = [];
try {
  const aData = $('DNS A Records').first().json;
  aRecords = (aData.Answer || []).filter(r => r.type === 1).map(r => r.data);
} catch(e) {}

// Parse MX records
let mxRecords = [];
try {
  const mxData = $('DNS MX Records').first().json;
  mxRecords = (mxData.Answer || []).filter(r => r.type === 15).map(r => r.data);
} catch(e) {}

// Parse TXT records
let txtRecords = [];
try {
  const txtData = $('DNS TXT Records').first().json;
  txtRecords = (txtData.Answer || []).filter(r => r.type === 16).map(r => r.data);
} catch(e) {}

// Parse crt.sh subdomains
let subdomains = new Set();
try {
  const crtData = $('Certificate Transparency').first().json;
  if (Array.isArray(crtData)) {
    crtData.forEach(entry => {
      const names = (entry.name_value || '').split('\n');
      names.forEach(n => {
        const clean = n.trim().replace(/^\*\./, '').toLowerCase();
        if (clean && clean !== domain && clean.endsWith('.' + domain)) {
          subdomains.add(clean);
        }
      });
    });
  }
} catch(e) {}

return [{ json: {
  domain,
  engagement_id: engId,
  asset_id: assetId,
  scan_job_id: scanJobId,
  a_records: aRecords,
  mx_records: mxRecords,
  txt_records: txtRecords,
  discovered_subdomains: Array.from(subdomains).slice(0, 100),
  discovery_count: subdomains.size
} }];

const data = $input.first().json;
const subdomains = data.discovered_subdomains || [];
return subdomains.map(sub => ({ json: {
  asset_value: sub,
  asset_type: 'subdomain',
  engagement_id: data.engagement_id,
  notes: 'Discovered via crt.sh CT log'
} }));

